import React, { useState, useEffect } from 'react';
import axios from 'axios';
import io from 'socket.io-client';  // ✅ default import
import './index.css';

const API_URL = 'http://localhost:3001';

// Types
interface FxRateData {
  rate: number;
  base: string;
  quote: string;
  timestamp: string;
}

interface FeeBreakdown {
  amount: number;
  currency: string;
  bdtAmount: number;
  totalFee: number;
  bankFees: number;
  techFee: number;
  receiverGets: number;
  yourProfit: number;
  opsCost: number;
}

const CURRENCIES: Record<string, { name: string; flag: string }> = {
  AED: { name: 'UAE Dirham', flag: '🇦🇪' },
  USD: { name: 'US Dollar', flag: '🇺🇸' },
  SAR: { name: 'Saudi Riyal', flag: '🇸🇦' },
  MYR: { name: 'Malaysian Ringgit', flag: '🇲🇾' },
  GBP: { name: 'British Pound', flag: '🇬🇧' },
  EUR: { name: 'Euro', flag: '🇪🇺' }
};

function App() {
  const [amount, setAmount] = useState('');
  const [currency, setCurrency] = useState('AED');
  const [receiver, setReceiver] = useState('');
  const [fxRate, setFxRate] = useState<FxRateData | null>(null);
  const [feeBreakdown, setFeeBreakdown] = useState<FeeBreakdown | null>(null);
  const [loading, setLoading] = useState(false);
  const [txId, setTxId] = useState<string | null>(null);
  const [status, setStatus] = useState('');

  // WebSocket connection
  useEffect(() => {
    const socket = io(API_URL);
    socket.on('status_update', (data: { transactionId: string; status: string; message: string }) => {
      setStatus(data.message);
      if (data.status === 'completed') alert('✅ Money sent!');
    });
    return () => { socket.disconnect(); };
  }, []);

  // Fetch live FX rate every 30 seconds
  useEffect(() => {
    const fetchFxRate = async () => {
      try {
        const res = await axios.get<{ success: boolean; data: FxRateData }>(
          `${API_URL}/api/fx/current?base=${currency}&quote=BDT`
        );
        setFxRate(res.data.data);
      } catch (err) {
        console.log('Rate fetch failed, using default');
      }
    };
    fetchFxRate();
    const interval = setInterval(fetchFxRate, 30000);
    return () => clearInterval(interval);
  }, [currency]);

  const calculateFees = async () => {
    if (!amount || !receiver) return;
    try {
      const res = await axios.post<FeeBreakdown>(`${API_URL}/api/fees/calculate`, {
        amount: parseFloat(amount),
        currency,
        receiver,
        fxRate: fxRate?.rate
      });
      setFeeBreakdown(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const handleSend = async () => {
    setLoading(true);
    setStatus('Starting transaction...');
    try {
      const res = await axios.post<{ transactionId: string; status: string }>(
        `${API_URL}/api/remittance/initiate`,
        {
          amount: parseFloat(amount),
          currency,
          receiver,
          fxRate: fxRate?.rate,
        }
      );
      setTxId(res.data.transactionId);
      setStatus('Transaction sent. Waiting...');
    } catch (err: any) {
      setStatus('Error: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen overflow-hidden relative">
      {/* Wavy background */}
      <div className="wavy-bg"></div>

      {/* Floating particles */}
      {[...Array(50)].map((_, i) => (
        <div
          key={i}
          className="particle"
          style={{
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`,
            width: `${Math.random() * 6 + 2}px`,
            height: `${Math.random() * 6 + 2}px`,
            background: i % 3 === 0 ? '#f42a41' : 'rgba(255,255,255,0.3)',
            animationDelay: `${Math.random() * 10}s`,
            animationDuration: `${Math.random() * 15 + 10}s`,
          }}
        />
      ))}

      {/* Red orb – simple div (no Flag3D) */}
      <div className="absolute top-20 right-20 w-64 h-64 md:w-48 md:h-48 sm:w-32 sm:h-32 sm:top-10 sm:right-10">
        <div className="w-full h-full rounded-full orb animate-float" />
      </div>

      {/* Main content */}
      <div className="relative z-10 max-w-6xl mx-auto px-4 py-12">
        <header className="text-center mb-16">
          <h1 className="text-6xl font-bold text-white mb-4 gradient-text">
            Send Money to Bangladesh
          </h1>
          <p className="text-2xl text-green-100">Fast • Secure • 1.70% total fee</p>
        </header>

        <div className="flex justify-center">
          <div className="w-full max-w-2xl card-3d">
            <div className="bg-white/10 backdrop-blur-xl rounded-3xl shadow-2xl border border-white/20 p-8 text-white">

              {/* Live rate banner */}
              {fxRate && (
                <div className="mb-8 p-4 bg-black/20 rounded-2xl border border-green-400/30 flex flex-col sm:flex-row justify-between items-center gap-2">
                  <span className="text-lg">🇧🇩 1 {currency} =</span>
                  <span className="text-3xl font-bold text-green-300">
                    {fxRate.rate.toFixed(4)} BDT
                  </span>
                  <span className="text-sm opacity-75">live</span>
                </div>
              )}

              <div className="space-y-6">
                <div>
                  <label className="block text-sm font-medium mb-2">Amount</label>
                  <div className="flex flex-col sm:flex-row gap-2">
                    <input
                      type="number"
                      value={amount}
                      onChange={(e) => setAmount(e.target.value)}
                      className="flex-1 bg-white/20 border border-white/30 rounded-xl px-4 py-3 text-white placeholder-white/50 focus:outline-none focus:ring-2 focus:ring-red-400"
                      placeholder="1000"
                    />
                    <select
                      value={currency}
                      onChange={(e) => setCurrency(e.target.value)}
                      className="bg-white/20 border border-white/30 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-red-400"
                    >
                      {Object.entries(CURRENCIES).map(([code, info]) => (
                        <option key={code} value={code} className="bg-gray-800">
                          {info.flag} {code} – {info.name}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium mb-2">bKash Number</label>
                  <input
                    type="text"
                    value={receiver}
                    onChange={(e) => setReceiver(e.target.value)}
                    className="w-full bg-white/20 border border-white/30 rounded-xl px-4 py-3 text-white placeholder-white/50 focus:outline-none focus:ring-2 focus:ring-red-400"
                    placeholder="01XXXXXXXXX"
                  />
                </div>

                <button
                  onClick={calculateFees}
                  className="w-full bg-gradient-to-r from-red-600 to-red-500 hover:from-red-700 hover:to-red-600 text-white font-bold py-4 rounded-xl shadow-lg transition-all transform hover:scale-105"
                >
                  Calculate Fees
                </button>

                {feeBreakdown && (
                  <div className="mt-8 p-6 bg-black/30 backdrop-blur rounded-2xl border border-green-400/30">
                    <h3 className="text-xl font-bold mb-4">Fee Breakdown</h3>
                    <div className="space-y-3">
                      <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-1">
                        <span>You send</span>
                        <span className="font-mono">{feeBreakdown.amount} {feeBreakdown.currency}</span>
                      </div>
                      <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-1">
                        <span>Converted</span>
                        <span className="font-mono">৳{feeBreakdown.bdtAmount.toFixed(2)}</span>
                      </div>
                      <div className="h-px bg-white/20 my-2" />
                      <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-1 text-green-300">
                        <span>Receiver gets</span>
                        <span className="font-bold text-2xl">৳{feeBreakdown.receiverGets.toFixed(2)}</span>
                      </div>
                      <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-1 text-sm text-red-300">
                        <span>Total fee (1.70%)</span>
                        <span>-৳{feeBreakdown.totalFee.toFixed(2)}</span>
                      </div>
                      <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-1 text-xs text-white/60">
                        <span>Bank fees (0.70%)</span>
                        <span>৳{feeBreakdown.bankFees.toFixed(2)}</span>
                      </div>
                      <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-1 text-xs text-white/60">
                        <span>Your profit (0.60%)</span>
                        <span className="text-green-400">+৳{feeBreakdown.yourProfit.toFixed(2)}</span>
                      </div>
                    </div>

                    <button
                      onClick={handleSend}
                      disabled={loading}
                      className="w-full mt-6 bg-green-600 hover:bg-green-700 text-white font-bold py-4 rounded-xl shadow-lg disabled:opacity-50"
                    >
                      {loading ? 'Processing...' : 'Confirm & Send'}
                    </button>
                  </div>
                )}

                {status && (
                  <div className="mt-4 p-4 bg-white/10 rounded-xl text-center">
                    {status}
                  </div>
                )}
                {txId && (
                  <div className="mt-2 text-xs text-white/50 text-center">
                    Transaction ID: {txId}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
